import{_ as t,o as s,c as i,ag as a}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Running the RustChat Environment","description":"","frontmatter":{},"headers":[],"relativePath":"development/local-setup.md","filePath":"development/local-setup.md","lastUpdated":1775719799000}'),o={name:"development/local-setup.md"};function n(l,e,r,d,c,h){return s(),i("div",null,[...e[0]||(e[0]=[a(`<h1 id="running-the-rustchat-environment" tabindex="-1">Running the RustChat Environment <a class="header-anchor" href="#running-the-rustchat-environment" aria-label="Permalink to &quot;Running the RustChat Environment&quot;">​</a></h1><p>RustChat is containerized using Docker Compose for easy setup and development. The environment includes:</p><ul><li><strong>Backend</strong>: Rust (Axum) API</li><li><strong>Frontend</strong>: Vue 3 + Vite (Served via Nginx)</li><li><strong>Postgres</strong>: Database</li><li><strong>Redis</strong>: Caching</li><li><strong>MinIO</strong>: S3-compatible object storage</li><li><strong>Meilisearch</strong>: (Optional) Full-text search engine</li></ul><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li><a href="https://docs.docker.com/get-docker/" target="_blank" rel="noreferrer">Docker</a> installed.</li><li><a href="https://docs.docker.com/compose/install/" target="_blank" rel="noreferrer">Docker Compose</a> installed (usually included with Docker Desktop).</li></ul><h2 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h2><ol><li><p><strong>Build and Start Services:</strong> Run the following command in the project root to build the backend and frontend images and start all services:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --build</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span></span></code></pre></div><p><em>The <code>-d</code> flag runs containers in detached mode (background).</em></p></li><li><p><strong>Verify Services:</strong> Check the status of the containers:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ps</span></span></code></pre></div><p>All services (<code>backend</code>, <code>frontend</code>, <code>postgres</code>, <code>redis</code>, <code>minio</code>, <code>createbuckets</code>) should be <code>Up</code> (or <code>Exited (0)</code> for <code>createbuckets</code>).</p></li><li><p><strong>Access the Application:</strong></p><ul><li><strong>Frontend:</strong> <a href="http://localhost:8080" target="_blank" rel="noreferrer">http://localhost:8080</a></li><li><strong>Backend API:</strong> <a href="http://localhost:3000" target="_blank" rel="noreferrer">http://localhost:3000</a></li><li><strong>MinIO Console:</strong> <a href="http://localhost:9001" target="_blank" rel="noreferrer">http://localhost:9001</a> (use your <code>RUSTFS_ACCESS_KEY</code> / <code>RUSTFS_SECRET_KEY</code>)</li><li><strong>Meilisearch:</strong> <a href="http://localhost:7700" target="_blank" rel="noreferrer">http://localhost:7700</a> (if enabled)</li></ul></li></ol><h2 id="development-mode" tabindex="-1">Development Mode <a class="header-anchor" href="#development-mode" aria-label="Permalink to &quot;Development Mode&quot;">​</a></h2><p>If you are actively developing code:</p><h3 id="backend-development" tabindex="-1">Backend Development <a class="header-anchor" href="#backend-development" aria-label="Permalink to &quot;Backend Development&quot;">​</a></h3><p>You can run the backend locally while keeping infrastructure services (DB, Redis, MinIO) in Docker.</p><ol><li>Stop the <code>backend</code> container if running: <code>docker compose stop backend</code></li><li>Run cargo locally:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> backend</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span></code></pre></div><em>Note: Ensure your local <code>.env</code> file points to localhost ports for DB/Redis/MinIO.</em></li></ol><h3 id="frontend-development" tabindex="-1">Frontend Development <a class="header-anchor" href="#frontend-development" aria-label="Permalink to &quot;Frontend Development&quot;">​</a></h3><ol><li>Stop the <code>frontend</code> container if running: <code>docker compose stop frontend</code></li><li>Run npm locally:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> frontend</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span></code></pre></div><em>Access at <a href="http://localhost:5173" target="_blank" rel="noreferrer">http://localhost:5173</a>.</em></li></ol><h2 id="security-modes-dev-vs-prod" tabindex="-1">Security Modes (Dev vs Prod) <a class="header-anchor" href="#security-modes-dev-vs-prod" aria-label="Permalink to &quot;Security Modes (Dev vs Prod)&quot;">​</a></h2><p>RustChat changes behavior based on <code>RUSTCHAT_ENVIRONMENT</code>.</p><ul><li><code>development</code> (default): CORS is permissive unless you set <code>RUSTCHAT_CORS_ALLOWED_ORIGINS</code>.</li><li><code>production</code>: CORS is deny-by-default unless <code>RUSTCHAT_CORS_ALLOWED_ORIGINS</code> is explicitly set.</li></ul><p>Recommended production settings:</p><ul><li>Set <code>RUSTCHAT_ENVIRONMENT=production</code></li><li>Set <code>RUSTCHAT_CORS_ALLOWED_ORIGINS</code> to your exact frontend origins (comma-separated)</li><li>Use strong secrets for <code>RUSTCHAT_JWT_SECRET</code> and <code>RUSTCHAT_ENCRYPTION_KEY</code></li><li>Terminate TLS at the reverse proxy/load balancer (HTTPS at the edge)</li><li>Use encrypted SSO client secrets (stored via Admin UI/API)</li><li>Set TURN credentials explicitly if <code>TURN_SERVER_ENABLED=true</code></li><li>Query-token compatibility is removed (<code>RUSTCHAT_SECURITY_OAUTH_TOKEN_DELIVERY=query</code> and <code>RUSTCHAT_SECURITY_WS_ALLOW_QUERY_TOKEN=true</code> are rejected at startup)</li><li>If <code>RUSTCHAT_SITE_URL</code> is set in production, it must use <code>https://</code>; <code>RUSTCHAT_CORS_ALLOWED_ORIGINS</code> entries must also be <code>https://</code> only.</li></ul><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><ul><li><strong>Database Connection Errors:</strong> Ensure the <code>postgres</code> container is healthy (<code>docker compose ps</code>).</li><li><strong>S3 Upload Failures:</strong> Ensure the <code>createbuckets</code> service ran successfully. You can manually create the bucket in MinIO Console if needed.</li><li><strong>Rebuild:</strong> If you change dependencies or Dockerfiles, force a rebuild:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --build</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span></span></code></pre></div></li></ul>`,21)])])}const k=t(o,[["render",n]]);export{u as __pageData,k as default};
